{"command": "curl -s "https://api.thingspeak.com/channels/2785218/feeds.json?results=288" | python3 -c "
import json, sys
from datetime import datetime

data = json.load(sys.stdin)
feeds = data.get('feeds', [])

# Parse fields
temp, hum, lux, soil = [], [], [], []
for f in feeds:
    if f.get('field1'): temp.append(float(f['field1']))
    if f.get('field2'): hum.append(float(f['field2']))
    if f.get('field3'): lux.append(float(f['field3']))
    if f.get('field4'): soil.append(float(f['field4']))

def stats(arr):
    if not arr: return None, None, None, 0
    return round(sum(arr)/len(arr),1), min(arr), max(arr), len(arr)

t_avg, t_min, t_max, t_cnt = stats(temp)
h_avg, h_min, h_max, h_cnt = stats(hum)
l_avg, l_min, l_max, l_cnt = stats(lux)
s_avg, s_min, s_max, s_cnt = stats(soil)

print(f'TEMP|{t_avg}|{t_min}|{t_max}|{t_cnt}')
print(f'HUM|{h_avg}|{h_min}|{h_max}|{h_cnt}')
print(f'LUX|{l_avg}|{l_min}|{l_max}|{l_cnt}')
print(f'SOIL|{s_avg}|{s_min}|{s_max}|{s_cnt}')
print(f'CHANNEL|{data.get(\"channel\",{}).get(\"name\",\"\")}')
